arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService
@implements IDisposable

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    @* Left Sidebar - Channel List *@
    <aside class="chat-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-description">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* Main Message Area *@
    <main class="chat-main @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="main-header">
                <h2># @_activeChannel.Name</h2>
                <p>@_activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScrollAsync">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages...</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var message in _messages)
                    {
                        <div class="message-item" @onmouseenter="() => _hoveredMessageId = message.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-header">
                                <span class="message-author">@message.Author</span>
                                <span class="message-time">@FormatRelativeTime(message.SentAt)</span>
                            </div>
                            <div class="message-content">@message.Content</div>

                            @if (message.Reactions.Count > 0)
                            {
                                <div class="message-reactions">
                                    @foreach (var reaction in message.Reactions)
                                    {
                                        <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </span>
                                    }
                                </div>
                            }

                            @if (_threadSummaries.TryGetValue(message.Id, out var summary))
                            {
                                <a class="thread-link" @onclick="() => OpenThreadAsync(message)" @onclick:preventDefault>
                                    @summary.ReplyCount replies &middot; Last reply @FormatRelativeTime(summary.LastReplyAt)
                                </a>
                            }

                            @if (_hoveredMessageId == message.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(message)" title="Reply in thread">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(message.Id)" title="Add reaction">
                                        😀 React
                                    </button>
                                </div>

                                @if (_emojiPickerMessageId == message.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in _commonEmojis)
                                        {
                                            <button class="emoji-btn" @onclick="() => AddReactionAsync(message.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" @bind="_newMessageContent" @bind:event="oninput"
                          placeholder="Type a message..." @onkeydown="OnMessageKeyDownAsync"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageContent)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* Right Panel - Thread View *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">&times;</button>
            </div>

            <div class="thread-root-message">
                <div class="message-header">
                    <span class="message-author">@_threadRootMessage.Author</span>
                    <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                </div>
                <div class="message-content">@_threadRootMessage.Content</div>
            </div>

