@code {
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private string _newMessageContent = string.Empty;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private bool _loadingMore;
    private int _messageSkip;
    private const int PageSize = 30;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _threadReplyContent = string.Empty;

    private ElementReference _messageListRef;
    private CancellationTokenSource _cts = new();

    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messageSkip = 0;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messageSkip = _messages.Count;
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);
        _emojiPickerMessageId = null;

        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task OnMessageListScrollAsync()
    {
        // This would be enhanced with JS interop for precise scroll detection.
        // For now, provides the mechanism for loading older messages.
    }

    public async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore || _activeChannelId is null) return;
        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);
        if (older.Count > 0)
        {
            _messages = older.Concat(_messages ?? []).ToList();
            _messageSkip += older.Count;
            BuildThreadSummaries();
        }
        _loadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageContent) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageContent.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _newMessageContent = string.Empty;
    }

    private async Task OnMessageKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
        _threadReplyContent = string.Empty;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyContent) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyContent.Trim(), _threadRootMessage.Id);
        _threadMessages ??= [];
        _threadMessages.Add(reply);
        _threadReplyContent = string.Empty;

        // Update thread summary in main view
        if (_threadSummaries.ContainsKey(_threadRootMessage.Id))
        {
            var existing = _threadSummaries[_threadRootMessage.Id];
            _threadSummaries[_threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(_threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task OnThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messageSkip);
        }
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }

    public void Dispose()
    {
        _cts.Cancel();
        _cts.Dispose();
    }
}

